PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?year WHERE {
  ?person wdt:P952 wd:Q142 ; wdt:P4012 "carne y vino" @es ; wdt:P570 ?deathDate .
  BIND(YEAR(?deathDate) AS ?year)
}

